INSERT INTO `message_templates` (`id`, `name`, `subject`, `content`, `variables`, `is_active`, `created_at`, `updated_at`) VALUES
	(1, 'Bulletin trimestriel', 'Bulletin de notes - {student_name}', 'Bonjour {parent_name},\n\nVeuillez trouver ci-joint le bulletin de notes de {student_name} pour le {period}.\n\nCordialement,\nL\'équipe pédagogique', '["student_name", "parent_name", "period"]', 1, '2025-08-23 11:27:38', '2025-08-23 11:27:38'),
	(2, 'Absence non justifiée', 'Absence de {student_name}', 'Bonjour {parent_name},\n\nNous vous informons que {student_name} a été absent(e) le {date} sans justification.\n\nMerci de nous fournir une justification.\n\nCordialement,\nL\'équipe pédagogique', '["student_name", "parent_name", "date"]', 1, '2025-08-23 11:27:38', '2025-08-23 11:27:38'),
	(3, 'Rappel paiement', 'Rappel - Paiement des frais de scolarité', 'Bonjour {parent_name},\n\nNous vous rappelons que le paiement des frais de scolarité pour {student_name} est attendu.\n\nMontant restant : {amount} FCFA\n\nMerci de régulariser votre situation.\n\nCordialement,\nLe service comptabilité', '["parent_name", "student_name", "amount"]', 1, '2025-08-23 11:27:38', '2025-08-23 11:27:38'),
	(4, 'Conseil de discipline', 'Conseil de discipline - {student_name}', 'Bonjour {parent_name},\n\nNous vous convoquons à un conseil de discipline concernant {student_name} le {date} à {time}.\n\nMotif : {reason}\n\nVotre présence est obligatoire.\n\nCordialement,\nLa direction', '["parent_name", "student_name", "date", "time", "reason"]', 1, '2025-08-23 11:27:38', '2025-08-23 11:27:38'),
	(5, 'Félicitations', 'Félicitations - {student_name}', 'Bonjour {parent_name},\n\nNous avons le plaisir de vous féliciter pour les excellents résultats de {student_name}.\n\nContinuez ainsi !\n\nCordialement,\nL\'équipe pédagogique', '["parent_name", "student_name"]', 1, '2025-08-23 11:27:38', '2025-08-23 11:27:38');
